import React, { useState, useEffect, useCallback } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { toast } from 'react-toastify';
import { FaPlus, FaEdit, FaTrash, FaSync, FaUsers } from 'react-icons/fa';
import { employeeAPI, syncAPI } from '../services/api';
import DeleteConfirmation from './DeleteConfirmation';
import EmployeeSearch from './EmployeeSearch';

function EmployeeList({ onRefresh }) {
  const navigate = useNavigate();

  const [employees, setEmployees] = useState([]);
  const [loading, setLoading] = useState(true);

  const [departments, setDepartments] = useState([]);
  const [positions, setPositions] = useState([]);

  const [page, setPage] = useState(1);
  const [pageSize] = useState(10);
  const [totalPages, setTotalPages] = useState(0);
  const [total, setTotal] = useState(0);

  const [searchParams, setSearchParams] = useState({});

  const [showDeleteModal, setShowDeleteModal] = useState(false);
  const [selectedEmployee, setSelectedEmployee] = useState(null);

  const [syncingId, setSyncingId] = useState(null);

  const fetchEmployees = useCallback(async () => {
    setLoading(true);
    try {
      const response = await employeeAPI.search(searchParams, page, pageSize);
      setEmployees(response.data.employees);
      setTotalPages(response.data.total_pages);
      setTotal(response.data.total);
    } catch (error) {
      toast.error('Failed to fetch employees');
      console.error('Fetch employees error:', error);
    } finally {
      setLoading(false);
    }
  }, [page, pageSize, searchParams]);

  const fetchLookups = async () => {
    try {
      const [deptRes, posRes] = await Promise.all([
        employeeAPI.getDepartments(),
        employeeAPI.getPositions(),
      ]);
      setDepartments(deptRes.data);
      setPositions(posRes.data);
    } catch (error) {
      console.error('Failed to fetch lookups:', error);
    }
  };

  useEffect(() => {
    fetchEmployees();
  }, [fetchEmployees]);

  useEffect(() => {
    fetchLookups();
  }, []);

  const handleSearch = (params) => {
    setSearchParams(params);
    setPage(1);
  };

  const handleDeleteClick = (employee) => {
    setSelectedEmployee(employee);
    setShowDeleteModal(true);
  };

  const handleDeleteConfirm = async (cascadeDelete) => {
    try {
      await syncAPI.deleteEmployee(selectedEmployee.EmployeeID, false, cascadeDelete);
      toast.success(`Employee "${selectedEmployee.FullName}" deleted successfully`);
      setShowDeleteModal(false);
      setSelectedEmployee(null);
      fetchEmployees();
      if (onRefresh) onRefresh();
    } catch (error) {
      const errorMessage = error.response?.data?.detail?.message || 
                          error.response?.data?.detail || 
                          'Failed to delete employee';
      toast.error(errorMessage);
    }
  };

  const handleSyncEmployee = async (employee) => {
    setSyncingId(employee.EmployeeID);
    try {
      await syncAPI.syncEmployees([employee.EmployeeID]);
      toast.success(`Employee "${employee.FullName}" synced to payroll system`);
    } catch (error) {
      toast.error('Failed to sync employee to payroll');
      console.error('Sync error:', error);
    } finally {
      setSyncingId(null);
    }
  };

  const getStatusBadgeClass = (status) => {
    const statusMap = {
      'Đang làm việc': 'badge-success',
      'Thử việc': 'badge-warning',
      'Thực tập': 'badge-info',
      'Nghỉ phép': 'badge-info',
      'Nghỉ việc': 'badge-danger',
    };
    return statusMap[status] || 'badge-info';
  };

  const formatDate = (dateString) => {
    if (!dateString) return '-';
    return new Date(dateString).toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'short',
      day: 'numeric'
    });
  };

  const renderPagination = () => {
    if (totalPages <= 1) return null;

    const pages = [];
    let startPage = Math.max(1, page - 2);
    let endPage = Math.min(totalPages, startPage + 4);

    if (endPage - startPage < 4) {
      startPage = Math.max(1, endPage - 4);
    }

    for (let i = startPage; i <= endPage; i++) {
      pages.push(i);
    }

    return (
      <div className="pagination">
        <button
          className="pagination-btn"
          onClick={() => setPage(1)}
          disabled={page === 1}
        >
          First
        </button>
        <button
          className="pagination-btn"
          onClick={() => setPage(p => Math.max(1, p - 1))}
          disabled={page === 1}
        >
          Previous
        </button>

        {pages.map((pageNum) => (
          <button
            key={pageNum}
            className={`pagination-btn ${page === pageNum ? 'active' : ''}`}
            onClick={() => setPage(pageNum)}
          >
            {pageNum}
          </button>
        ))}

        <button
          className="pagination-btn"
          onClick={() => setPage(p => Math.min(totalPages, p + 1))}
          disabled={page === totalPages}
        >
          Next
        </button>
        <button
          className="pagination-btn"
          onClick={() => setPage(totalPages)}
          disabled={page === totalPages}
        >
          Last
        </button>

        <span className="pagination-info">
          Showing {(page - 1) * pageSize + 1} - {Math.min(page * pageSize, total)} of {total} employees
        </span>
      </div>
    );
  };

  return (
    <div>
      <div className="stats-grid">
        <div className="stat-card">
          <div className="stat-card-icon" style={{ background: '#bee3f8' }}>
            <FaUsers style={{ color: '#2b6cb0' }} />
          </div>
          <div className="stat-card-value">{total}</div>
          <div className="stat-card-label">Total Employees</div>
        </div>
      </div>

      <div className="card">
        <div className="card-header">
          <h2>
            <FaUsers style={{ marginRight: '10px' }} />
            Employee Management
          </h2>
          <Link to="/employees/new" className="btn btn-primary">
            <FaPlus />
            Add Employee
          </Link>
        </div>

        <div className="card-body">
          <EmployeeSearch
            onSearch={handleSearch}
            departments={departments}
            positions={positions}
          />

          {loading ? (
            <div className="loading">
              <div className="spinner"></div>
            </div>
          ) : (
            <>
              <div className="table-container">
                <table className="table">
                  <thead>
                    <tr>
                      <th>ID</th>
                      <th>Full Name</th>
                      <th>Email</th>
                      <th>Phone</th>
                      <th>Department</th>
                      <th>Position</th>
                      <th>Status</th>
                      <th>Hire Date</th>
                      <th>Actions</th>
                    </tr>
                  </thead>
                  <tbody>
                    {employees.length === 0 ? (
                      <tr>
                        <td colSpan="9" className="empty-state">
                          <div className="empty-state-content">
                            <FaUsers size={48} style={{ color: '#cbd5e0', marginBottom: '16px' }} />
                            <h3>No employees found</h3>
                            <p>Try adjusting your search filters or add a new employee.</p>
                            <Link to="/employees/new" className="btn btn-primary" style={{ marginTop: '16px' }}>
                              <FaPlus />
                              Add Employee
                            </Link>
                          </div>
                        </td>
                      </tr>
                    ) : (
                      employees.map((emp) => (
                        <tr key={emp.EmployeeID}>
                          <td>
                            <strong>#{emp.EmployeeID}</strong>
                          </td>
                          <td>
                            <div className="employee-name">
                              {emp.FullName}
                            </div>
                          </td>
                          <td>{emp.Email || '-'}</td>
                          <td>{emp.PhoneNumber || '-'}</td>
                          <td>{emp.DepartmentName || '-'}</td>
                          <td>{emp.PositionName || '-'}</td>
                          <td>
                            <span className={`badge ${getStatusBadgeClass(emp.Status)}`}>
                              {emp.Status}
                            </span>
                          </td>
                          <td>{formatDate(emp.HireDate)}</td>
                          <td>
                            <div className="action-buttons">
                              <button
                                className="action-btn action-btn-edit"
                                onClick={() => navigate(`/employees/${emp.EmployeeID}/edit`)}
                                title="Edit Employee"
                              >
                                <FaEdit />
                              </button>
                              <button
                                className={`action-btn action-btn-sync ${syncingId === emp.EmployeeID ? 'syncing' : ''}`}
                                onClick={() => handleSyncEmployee(emp)}
                                title="Sync to Payroll"
                                disabled={syncingId === emp.EmployeeID}
                              >
                                <FaSync className={syncingId === emp.EmployeeID ? 'spin' : ''} />
                              </button>
                              <button
                                className="action-btn action-btn-delete"
                                onClick={() => handleDeleteClick(emp)}
                                title="Delete Employee"
                              >
                                <FaTrash />
                              </button>
                            </div>
                          </td>
                        </tr>
                      ))
                    )}
                  </tbody>
                </table>
              </div>

              {renderPagination()}
            </>
          )}
        </div>
      </div>

      {showDeleteModal && selectedEmployee && (
        <DeleteConfirmation
          employee={selectedEmployee}
          onClose={() => {
            setShowDeleteModal(false);
            setSelectedEmployee(null);
          }}
          onConfirm={handleDeleteConfirm}
        />
      )}
    </div>
  );
}

export default EmployeeList;
